const rows = $input.all().map(item => item.json);

const riskColor = { low: '#22c55e', medium: '#f59e0b', high: '#f97316', critical: '#ef4444' };
const riskLabel = { low: 'Bajo', medium: 'Medio', high: 'Alto', critical: 'Crítico' };

const cards = rows.map(r => {
  const color = riskColor[r.risk_level] || '#6b7280';
  const label = riskLabel[r.risk_level] || r.risk_level;
  const date = new Date(r.created_at).toLocaleString('es-MX', { timeZone: 'America/Mexico_City' });
  return `
  <div class="card" data-id="${r.decision_id}">
    <div class="card-header">
      <span class="agent-badge">${r.agent_role}</span>
      <span class="risk-badge" style="background:${color}">${label}</span>
    </div>
    <div class="card-type">${r.decision_type.replace(/_/g, ' ')}</div>
    <div class="card-summary">${r.input_summary || '—'}</div>
    <div class="card-rec"><strong>Recomendación:</strong> ${r.recommendation || '—'}</div>
    <div class="card-meta">${date} · Confianza: ${Math.round((r.confidence || 0) * 100)}%</div>
    <div class="card-actions">
      <button class="btn approve" onclick="decide('${r.decision_id}', 'approved')">✅ Aprobar</button>
      <button class="btn reject" onclick="decide('${r.decision_id}', 'rejected')">❌ Rechazar</button>
    </div>
  </div>`;
}).join('');

const html = `<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>PetSafe PM — Aprobaciones</title>
  <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet">
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: 'Inter', sans-serif; background: #0f172a; color: #e2e8f0; min-height: 100vh; }
    header { background: linear-gradient(135deg, #1e3a5f 0%, #0f2d4a 100%); padding: 24px 32px; border-bottom: 1px solid rgba(255,255,255,0.08); display: flex; align-items: center; gap: 16px; }
    header h1 { font-size: 1.4rem; font-weight: 700; }
    header p { font-size: 0.85rem; color: #94a3b8; }
    .badge-count { background: #ef4444; color: #fff; border-radius: 999px; padding: 2px 10px; font-size: 0.8rem; font-weight: 700; }
    main { max-width: 960px; margin: 40px auto; padding: 0 24px; }
    .grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(420px, 1fr)); gap: 20px; }
    .card { background: #1e293b; border: 1px solid rgba(255,255,255,0.07); border-radius: 14px; padding: 20px; display: flex; flex-direction: column; gap: 10px; transition: transform 0.2s, box-shadow 0.2s; }
    .card:hover { transform: translateY(-2px); box-shadow: 0 8px 30px rgba(0,0,0,0.4); }
    .card-header { display: flex; align-items: center; gap: 10px; }
    .agent-badge { background: #334155; color: #93c5fd; border-radius: 6px; padding: 3px 10px; font-size: 0.78rem; font-weight: 600; }
    .risk-badge { border-radius: 6px; padding: 3px 10px; font-size: 0.78rem; font-weight: 700; color: #fff; }
    .card-type { font-size: 0.72rem; color: #64748b; text-transform: uppercase; letter-spacing: 0.05em; }
    .card-summary { font-size: 0.9rem; font-weight: 500; color: #cbd5e1; }
    .card-rec { font-size: 0.85rem; color: #94a3b8; line-height: 1.5; }
    .card-meta { font-size: 0.75rem; color: #475569; }
    .card-actions { display: flex; gap: 10px; margin-top: 4px; }
    .btn { flex: 1; padding: 9px 0; border-radius: 8px; border: none; font-size: 0.85rem; font-weight: 600; cursor: pointer; transition: opacity 0.15s; }
    .btn:hover { opacity: 0.85; }
    .btn.approve { background: #16a34a; color: #fff; }
    .btn.reject { background: #7f1d1d; color: #fca5a5; }
    .empty { text-align: center; padding: 80px 20px; color: #475569; }
    .empty h2 { font-size: 1.2rem; margin-bottom: 8px; }
    .toast { position: fixed; bottom: 24px; right: 24px; background: #1e293b; border: 1px solid rgba(255,255,255,0.1); border-radius: 10px; padding: 14px 20px; font-size: 0.9rem; display: none; z-index: 999; }
  </style>
</head>
<body>
  <header>
    <div>
      <h1>🛡️ PetSafe PM — Hub de Aprobaciones</h1>
      <p>Decisiones de IA pendientes de revisión humana</p>
    </div>
    <span class="badge-count">${rows.length} pendiente${rows.length !== 1 ? 's' : ''}</span>
  </header>
  <main>
    ${rows.length > 0 ? '<div class="grid">' + cards + '</div>' : '<div class="empty"><h2>🎉 Todo aprobado</h2><p>No hay decisiones pendientes en este momento.</p></div>'}
  </main>
  <div class="toast" id="toast"></div>
  <script>
    async function decide(id, action) {
      const card = document.querySelector('[data-id="' + id + '"]');
      if (card) card.style.opacity = '0.4';
      try {
        const res = await fetch('/webhook/pm-approve', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ decision_id: id, action, approved_by: 'tech-lead' })
        });
        showToast(action === 'approved' ? '✅ Aprobado correctamente' : '❌ Rechazado correctamente');
        setTimeout(() => card?.remove(), 600);
      } catch(e) {
        showToast('⚠️ Error al procesar. Intenta de nuevo.');
        if (card) card.style.opacity = '1';
      }
    }
    function showToast(msg) {
      const t = document.getElementById('toast');
      t.textContent = msg;
      t.style.display = 'block';
      setTimeout(() => t.style.display = 'none', 3000);
    }
  </script>
</body>
</html>`;

return [{ json: { html } }];

const d = $json;
const action = $('Webhook - Approve Action').item.json.action;
const emoji = action === 'approved' ? '✅' : '❌';
const verb = action === 'approved' ? 'aprobada' : 'rechazada';
const content = `${emoji} **Decisión ${verb}** por el Tech Lead

**Agente:** ${d.agent_role}
**Tipo:** ${d.decision_type}
**Recomendación:** ${d.recommendation || '—'}

ID: \`${d.decision_id}\``;
return [{ json: { content } }];
